<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Doceria Delícia</title>

<style>
body{
    margin:0;
    font-family: Arial, sans-serif;
    background:#fff3f0;
}

nav{
    background:#ff6b6b;
    display:flex;
    justify-content:space-between;
    align-items:center;
    padding:15px 30px;
    color:white;
}

nav h2{
    margin:0;
}

nav ul{
    list-style:none;
    display:flex;
    gap:20px;
}

nav ul li{
    cursor:pointer;
}

.banner{
    background:url('https://via.placeholder.com/1200x400') center/cover;
    height:300px;
    display:flex;
    align-items:center;
    justify-content:center;
    color:white;
    text-shadow:2px 2px 5px rgba(0,0,0,0.5);
    font-size:32px;
    font-weight:bold;
}

.section{
    padding:30px;
    text-align:center;
}

.cards{
    display:grid;
    grid-template-columns: repeat(auto-fit,minmax(200px,1fr));
    gap:20px;
    margin-top:20px;
}

.card{
    background:white;
    padding:20px;
    border-radius:12px;
    box-shadow:0 4px 10px rgba(0,0,0,0.1);
    transition:0.3s;
}

.card:hover{
    transform:scale(1.05);
}


.btn{
    background:#ff6b6b;
    color:white;
    padding:12px 20px;
    border:none;
    border-radius:8px;
    cursor:pointer;
    margin-top:15px;
}

.btn:hover{
    background:#e74c3c;
}


footer{
    background:#333;
    color:white;
    text-align:center;
    padding:15px;
    margin-top:30px;
}
</style>
</head>

<body>

<nav>
    <h2>🍰 Doceria</h2>
    <ul>
        <li>Home</li>
        <li>Bolos</li>
        <li>Pedidos</li>
        <li>Contato</li>
    </ul>
</nav>

<div class="banner">
    Os melhores bolos de pote da cidade!
</div>

<div class="section">
    <h2>Destaques</h2>

    <div class="cards">
        <div class="card">
            <h3>Chocolate</h3>
            <p>Super cremoso e delicioso</p>
            <img src="data:image/jpeg;base64," alt=>
        </div>


        <div class="card">
            <h3>Morango</h3>
            <p>Fresco e irresistível</p>
            <img src="data:image/jpeg;base64," alt=>

        </div>

        <div class="card">
            <h3>Leite Ninho</h3>
            <p>O mais pedido!</p>
            <img src="https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRhN-0jRWjOgYI6ccCa5WTvEtHTkvYVT5tsPg&s" alt=>

        </div>
    </div>
</div>


<div class="section">
    <h2>Faça seu pedido agora 🍰</h2>
    <button class="btn">Ver Cardápio</button>
    <a href="produtos.blade.php">
</div>
</a>
<footer>
    © 2026 Doceria Delícia | Todos os direitos reservados
</footer>

</body>
</html>